import ast

def bounded_evaluate(expression: str, variables: dict[str, int], max_nodes: int = 32) -> int:
    """
    Evaluate a tiny arithmetic expression language with explicit resource bounds.

    Args:
        expression: String containing the arithmetic expression
        variables: Dictionary mapping variable names to integer values
        max_nodes: Maximum number of AST nodes allowed (default 32)

    Returns:
        Integer result of evaluating the expression

    Raises:
        ValueError: If expression is invalid or exceeds constraints
    """
    try:
        # Parse the expression into an AST
        tree = ast.parse(expression, mode='eval')
    except SyntaxError:
        raise ValueError("Invalid expression syntax")

    # Count nodes and validate the AST
    node_count = _count_and_validate_nodes(tree, variables)

    if node_count > max_nodes:
        raise ValueError(f"Expression exceeds maximum nodes limit: {node_count} > {max_nodes}")

    # Evaluate the AST
    return _evaluate_node(tree.body, variables)

def _count_and_validate_nodes(tree, variables):
    """Count AST nodes and validate that only allowed constructs are used."""
    node_count = 0

    for node in ast.walk(tree):
        node_count += 1

        # Check if this is an allowed node type
        if isinstance(node, (ast.Expression, ast.Constant, ast.Num, ast.Name, 
                           ast.BinOp, ast.UnaryOp, ast.Add, ast.Sub, ast.Mult, 
                           ast.FloorDiv, ast.USub, ast.Load)):
            continue
        else:
            raise ValueError(f"Unsupported AST node type: {type(node).__name__}")

    # Validate that all variables are defined
    for node in ast.walk(tree):
        if isinstance(node, ast.Name) and isinstance(node.ctx, ast.Load):
            if node.id not in variables:
                raise ValueError(f"Unknown variable: {node.id}")

    return node_count

def _evaluate_node(node, variables):
    """Recursively evaluate an AST node."""
    if isinstance(node, ast.Constant):
        # Python 3.8+ uses ast.Constant for literals
        if isinstance(node.value, int):
            return node.value
        else:
            raise ValueError("Only integer constants are supported")

    elif isinstance(node, ast.Num):
        # Older Python versions use ast.Num for numbers
        if isinstance(node.n, int):
            return node.n
        else:
            raise ValueError("Only integer constants are supported")

    elif isinstance(node, ast.Name):
        # Variable reference
        return variables[node.id]

    elif isinstance(node, ast.BinOp):
        # Binary operation
        left = _evaluate_node(node.left, variables)
        right = _evaluate_node(node.right, variables)

        if isinstance(node.op, ast.Add):
            return left + right
        elif isinstance(node.op, ast.Sub):
            return left - right
        elif isinstance(node.op, ast.Mult):
            return left * right
        elif isinstance(node.op, ast.FloorDiv):
            if right == 0:
                raise ValueError("Division by zero")
            return left // right
        else:
            raise ValueError(f"Unsupported binary operator: {type(node.op).__name__}")

    elif isinstance(node, ast.UnaryOp):
        # Unary operation
        operand = _evaluate_node(node.operand, variables)

        if isinstance(node.op, ast.USub):
            return -operand
        else:
            raise ValueError(f"Unsupported unary operator: {type(node.op).__name__}")

    else:
        raise ValueError(f"Unsupported node type: {type(node).__name__}")

